import { Link } from "react-router-dom";
import { questions } from "../data/questions";

function Dashboard() {
  return (
    <div className="dashboard-full">

      {/* Header */}
      <div className="dashboard-header">
        <h2>Dashboard</h2>
        <p>Questions posted by juniors</p>
      </div>

      {/* Questions */}
      {questions.map((q) => (
        <div key={q.id} className="dashboard-question">
          <h4>{q.title}</h4>
          <p>{q.description}</p>

          <div className="dashboard-footer">
            <span className="dashboard-tag">
              Asked by Junior
            </span>
            <Link to="/answers" className="dashboard-btn">
              View Answer
            </Link>
          </div>
        </div>
      ))}

      {/* Ask button */}
      <Link to="/ask" className="dashboard-ask">
        Ask New Question
      </Link>

    </div>
  );
}

export default Dashboard;
